const PersonIcon = ({ position, color = '#FFD700', confidence = 0.5 }) => {
  const group = useRef()
  const { scene, animations } = useGLTF('/models/person.glb')
  const { actions } = useAnimations(animations, group)
  const clone = React.useMemo(() => scene.clone(true), [scene])

  useEffect(() => {
    clone.traverse((child) => {
      if (child.isMesh) {
        child.castShadow = true
        child.material = child.material.clone()
        child.material.emissive = new THREE.Color(color)
        child.material.emissiveIntensity = 0.15 + confidence * 0.3
      }
    })
    const walkAction = actions['Walk'] || actions['mixamo.com'] || Object.values(actions)[0]
    if (walkAction) { walkAction.reset().fadeIn(0.3).play() }
    return () => walkAction?.fadeOut(0.3)
  }, [clone, actions, color, confidence])

  useFrame(({ clock }) => {
    if (!group.current) return
    const t = clock.elapsedTime
    group.current.position.y = position[1] + Math.sin(t * 1.1) * 0.04
    if (confidence > 0.8) {
      clone.traverse(child => {
        if (child.isMesh) child.material.emissiveIntensity = 0.3 + Math.abs(Math.sin(t * 4)) * 0.6
      })
    }
  })

  return (
    <group ref={group} position={position} dispose={null}>
      <primitive object={clone} scale={[0.012, 0.012, 0.012]} rotation={[0, Math.PI, 0]} />
    </group>
  )
}
