CarIcon_component.implementation:
const CarIcon = ({ position, color = '#00FF88', confidence = 0.5 }) => {
  const group = useRef()
  const { scene } = useGLTF('/models/car.glb')
  const clone = React.useMemo(() => scene.clone(true), [scene])
  const wheelRefs = useRef([])

  useEffect(() => {
    wheelRefs.current = []
    clone.traverse((child) => {
      if (child.isMesh) {
        child.castShadow = true
        child.material = child.material.clone()
        if (!child.name.toLowerCase().includes('wheel') && !child.name.toLowerCase().includes('tyre')) {
          child.material.color = new THREE.Color(color)
          child.material.emissive = new THREE.Color(color)
          child.material.emissiveIntensity = 0.1 + confidence * 0.2
          child.material.roughness = 0.2
          child.material.metalness = 0.8
        }
      }
      if (child.name.toLowerCase().includes('wheel') || child.name.toLowerCase().includes('tyre')) {
        wheelRefs.current.push(child)
      }
    })
  }, [clone, color, confidence])

  useFrame(({ clock }) => {
    if (!group.current) return
    const t = clock.elapsedTime
    group.current.position.y = position[1] + Math.sin(t * 0.8) * 0.025
    wheelRefs.current.forEach(w => { w.rotation.x += 0.04 })
    if (confidence > 0.8) {
      clone.traverse(child => {
        if (child.isMesh && !child.name.toLowerCase().includes('wheel')) {
          child.material.emissiveIntensity = 0.2 + Math.abs(Math.sin(t * 3)) * 0.5
        }
      })
    }
  })

  return (
    <group ref={group} position={position} dispose={null}>
      <primitive object={clone} scale={[0.8, 0.8, 0.8]} />
    </group>
  )
}
