const MotorcycleIcon = ({ position, color = '#FF8C00', confidence = 0.5 }) => {
  const group = useRef()
  const { scene } = useGLTF('/models/motorcycle.glb')
  const clone = React.useMemo(() => scene.clone(true), [scene])

  useEffect(() => {
    clone.traverse((child) => {
      if (child.isMesh) {
        child.castShadow = true
        child.material = child.material.clone()
        if (!child.name.toLowerCase().includes('wheel') && !child.name.toLowerCase().includes('tyre')) {
          child.material.color = new THREE.Color(color)
          child.material.emissive = new THREE.Color(color)
          child.material.emissiveIntensity = 0.15 + confidence * 0.25
          child.material.roughness = 0.25
          child.material.metalness = 0.7
        }
      }
    })
  }, [clone, color, confidence])

  useFrame(({ clock }) => {
    if (!group.current) return
    const t = clock.elapsedTime
    group.current.position.y = position[1] + Math.sin(t * 1.3) * 0.035
    group.current.rotation.z = Math.sin(t * 0.7) * 0.04
    if (confidence > 0.8) {
      clone.traverse(child => {
        if (child.isMesh) child.material.emissiveIntensity = 0.2 + Math.abs(Math.sin(t * 3.5)) * 0.55
      })
    }
  })

  return (
    <group ref={group} position={position} dispose={null}>
      <primitive object={clone} scale={[0.6, 0.6, 0.6]} rotation={[0, Math.PI / 2, 0]} />
    </group>
  )
}
