LoadingFallback_component.implementation:
const LoadingFallback = ({ position, color }) => {
  const mesh = useRef()
  useFrame(({ clock }) => {
    if (mesh.current) mesh.current.rotation.y = clock.elapsedTime * 2
  })
  return (
    <mesh ref={mesh} position={position}>
      <octahedronGeometry args={[0.25]} />
      <meshStandardMaterial color={color} emissive={color} emissiveIntensity={0.6} wireframe />
    </mesh>
  )
}

DetectionIcon_dispatcher.implementation:
const COLOR_MAP = { person: '#FFD700', car: '#00FF88', motorcycle: '#FF8C00' }

const DetectionIcon = ({ detection }) => {
  const { object, camera_zone, confidence, position: detPos } = detection

  const ZONE_OFFSETS = { left: [-2.5, 0, 0], right: [2.5, 0, 0], rear: [0, 0, 3] }
  const offset = ZONE_OFFSETS[camera_zone] || [0, 0, 0]
  const worldPos = detPos
    ? [detPos.x, detPos.y, detPos.z]
    : offset

  const color = COLOR_MAP[object] || '#ffffff'
  const fallback = <LoadingFallback position={worldPos} color={color} />

  return (
    <Suspense fallback={fallback}>
      {object === 'person'     && <PersonIcon     position={worldPos} color={color} confidence={confidence} />}
      {object === 'car'        && <CarIcon        position={worldPos} color={color} confidence={confidence} />}
      {object === 'motorcycle' && <MotorcycleIcon position={worldPos} color={color} confidence={confidence} />}
    </Suspense>
  )
}

export default DetectionIcon
